import{_ as s,o as e,c as a,ag as o}from"./chunks/framework.DQQHyi2x.js";const k=JSON.parse('{"title":"What are Hooks?","description":"","frontmatter":{},"headers":[],"relativePath":"hooks/index.md","filePath":"hooks/index.md"}'),i={name:"hooks/index.md"};function n(l,t,d,h,r,c){return e(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="what-are-hooks" tabindex="-1">What are Hooks? <a class="header-anchor" href="#what-are-hooks" aria-label="Permalink to &quot;What are Hooks?&quot;">​</a></h1><p>Hooks are the mechanism by which Contenox gives a model access to real-world actions. Instead of generating text, the model calls a hook to read files, run commands, query APIs, or fire HTTP requests — and gets the result back as context for its next reply.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chain starts</span></span>
<span class="line"><span>  └─ FetchTools: each listed hook returns its tool schemas</span></span>
<span class="line"><span>       └─ Schemas are sent to the model alongside the prompt</span></span>
<span class="line"><span>            └─ Model returns a tool call</span></span>
<span class="line"><span>                 └─ execute_tool_calls runs the hook</span></span>
<span class="line"><span>                      └─ Result appended to history → model continues</span></span></code></pre></div><p>In your chain JSON, specify which hooks the task can use via the <code>execute_config.hooks</code> allowlist:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;execute_config&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;qwen2.5:7b&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;provider&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ollama&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;hooks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local_fs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nws&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local_shell&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Pattern support:</p><table tabindex="0"><thead><tr><th>Value</th><th>Meaning</th></tr></thead><tbody><tr><td>field absent</td><td>All registered hooks</td></tr><tr><td><code>[]</code></td><td>No hooks exposed to the model</td></tr><tr><td><code>[&quot;*&quot;]</code></td><td>All registered hooks (explicit)</td></tr><tr><td><code>[&quot;a&quot;, &quot;b&quot;]</code></td><td>Only the named hooks</td></tr><tr><td><code>[&quot;*&quot;, &quot;!plan_manager&quot;]</code></td><td>All except <code>plan_manager</code></td></tr></tbody></table><p>Unknown names in an exact list are silently ignored — if <code>local_shell</code> is disabled the chain still runs.</p><p>Use <span><code>{{hookservice:list}}</code></span> in your <code>system_instruction</code> to inject the live tool manifest. This macro respects the task&#39;s <code>hooks</code> allowlist — the model only sees what the task permits:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;system_instruction&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;You are a helpful assistant. Available tools: {{hookservice:list}}.&quot;</span></span></code></pre></div><h2 id="hook-types" tabindex="-1">Hook types <a class="header-anchor" href="#hook-types" aria-label="Permalink to &quot;Hook types&quot;">​</a></h2><p>Contenox ships with four built-in local hooks and supports unlimited remote hooks:</p><table tabindex="0"><thead><tr><th>Hook name</th><th>Type</th><th>Always available</th><th>What it does</th></tr></thead><tbody><tr><td><code>local_fs</code></td><td>Local</td><td>✅</td><td>Read, write, and search files within a configured directory</td></tr><tr><td><code>webhook</code></td><td>Local</td><td>✅</td><td>Call any HTTP endpoint</td></tr><tr><td><code>js_execution</code></td><td>Local</td><td>✅</td><td>Execute sandboxed JavaScript</td></tr><tr><td><code>local_shell</code></td><td>Local</td><td>Opt-in (<code>--shell</code>)</td><td>Run arbitrary shell commands</td></tr><tr><td><em>your name</em></td><td>Remote</td><td>Register with <code>contenox hook add</code></td><td>Any OpenAPI v3 service</td></tr></tbody></table><h2 id="choosing-the-right-hook" tabindex="-1">Choosing the right hook <a class="header-anchor" href="#choosing-the-right-hook" aria-label="Permalink to &quot;Choosing the right hook&quot;">​</a></h2><ul><li><strong><code>local_fs</code></strong> — best for code analysis, file editing, report generation</li><li><strong><code>webhook</code></strong> — when the model needs to call a specific URL you control</li><li><strong><code>js_execution</code></strong> — lightweight computation or data transformation without shell access</li><li><strong><code>local_shell</code></strong> — full power; use only in trusted, sandboxed environments</li><li><strong>Remote hooks</strong> — turn any OpenAPI service into an agent tool; ideal for internal APIs, SaaS integrations, and team-shared tools</li></ul><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/hooks/remote.html">Remote Hooks</a> — register external APIs as agent tools</li><li><a href="/docs/hooks/local.html">Local Hooks</a> — built-in in-process hooks reference</li></ul>`,18)])])}const u=s(i,[["render",n]]);export{k as __pageData,u as default};
